import type {
    ListeningBandPosition,
    ListeningBankItem,
    ListeningCefr,
    ListeningMemoryLoad,
    ListeningNaturalness,
    ListeningReducedFormsPresence,
    ListeningReviewStatus,
} from "./listening-drill-bank";

type LowBandSeed = {
    id: string;
    chinese: string;
    referenceEnglish: string;
    targetEnglishVocab: string[];
    theme: string;
    scene: string;
    tags: string[];
    cefr: "A1" | "A2-" | "A2+";
    bandPosition: ListeningBandPosition;
    clauseCount: number;
    qualityScore: number;
    reviewStatus?: ListeningReviewStatus;
};

const ELO_WINDOWS: Record<LowBandSeed["cefr"], Record<ListeningBandPosition, { min: number; max: number }>> = {
    A1: {
        entry: { min: 0, max: 129 },
        mid: { min: 130, max: 264 },
        exit: { min: 265, max: 399 },
    },
    "A2-": {
        entry: { min: 400, max: 529 },
        mid: { min: 530, max: 664 },
        exit: { min: 665, max: 799 },
    },
    "A2+": {
        entry: { min: 800, max: 929 },
        mid: { min: 930, max: 1064 },
        exit: { min: 1065, max: 1199 },
    },
};

const BAND_DEFAULTS: Record<LowBandSeed["cefr"], {
    memoryLoad: ListeningMemoryLoad;
    spokenNaturalness: ListeningNaturalness;
    reducedFormsPresence: ListeningReducedFormsPresence;
}> = {
    A1: {
        memoryLoad: "low",
        spokenNaturalness: "low",
        reducedFormsPresence: "minimal",
    },
    "A2-": {
        memoryLoad: "low",
        spokenNaturalness: "medium",
        reducedFormsPresence: "minimal",
    },
    "A2+": {
        memoryLoad: "medium",
        spokenNaturalness: "medium",
        reducedFormsPresence: "some",
    },
};

function buildLowBandItem(seed: LowBandSeed): ListeningBankItem {
    const window = ELO_WINDOWS[seed.cefr][seed.bandPosition];
    const defaults = BAND_DEFAULTS[seed.cefr];
    const reviewStatus = getLowBandReviewStatus(seed);

    return {
        id: seed.id,
        status: "active",
        reviewStatus,
        mode: "listening",
        chinese: seed.chinese,
        reference_english: seed.referenceEnglish,
        target_english_vocab: seed.targetEnglishVocab,
        theme: seed.theme,
        scene: seed.scene,
        tags: seed.tags,
        eloMin: window.min,
        eloMax: window.max,
        bandPosition: seed.bandPosition,
        cefr: seed.cefr,
        clauseCount: seed.clauseCount,
        memoryLoad: defaults.memoryLoad,
        spokenNaturalness: defaults.spokenNaturalness,
        reducedFormsPresence: defaults.reducedFormsPresence,
        qualityScore: seed.qualityScore,
    };
}

const AUTO_REVIEW_PATTERNS = [
    /^Please bring the .+ here\.$/,
    /^The .+ is by the .+\.$/,
    /^[A-Z][A-Za-z]+ is near the .+\.$/,
    /^We start .+ at .+\.$/,
    /^Put the .+ on this .+\.$/,
    /^The .+ stays near .+\.$/,
    /^Please leave the .+ by the .+ before .+\.$/,
    /^I saved your .+ near the .+ today\.$/,
    /^The .+ is waiting at the .+ now\.$/,
    /^Bring the .+ to the .+ after .+\.$/,
    /^Our .+ starts in the .+ at .+\.$/,
    /^Please keep the .+ inside the .+ today\.$/,
    /^If the .+ stops, use the .+\.$/,
    /^When the .+ ends, call me near the .+\.$/,
    /^Because the .+ spilled, I changed my shirt\.$/,
    /^If the .+ feels crowded, wait by the .+\.$/,
    /^Since the .+ moved, meet me at the .+\.$/,
    /^When the .+ returns, ask about the .+\.$/,
    /^Because the .+ was crowded, we waited near the .+\.$/,
    /^If the .+ goes missing, check beside the .+\.$/,
];

function getLowBandReviewStatus(seed: LowBandSeed): ListeningReviewStatus {
    if (seed.reviewStatus) return seed.reviewStatus;
    if (!seed.tags.includes("auto")) return "curated";

    const isTemplateSentence = AUTO_REVIEW_PATTERNS.some((pattern) => pattern.test(seed.referenceEnglish));
    if (isTemplateSentence || seed.qualityScore <= 0.9) return "draft";

    return "curated";
}

function seed(
    id: string,
    chinese: string,
    referenceEnglish: string,
    targetEnglishVocab: string[],
    theme: string,
    scene: string,
    tags: string[],
    cefr: "A1" | "A2-" | "A2+",
    bandPosition: ListeningBandPosition,
    clauseCount: number,
    qualityScore: number,
    reviewStatus?: ListeningReviewStatus,
): LowBandSeed {
    return {
        id,
        chinese,
        referenceEnglish,
        targetEnglishVocab,
        theme,
        scene,
        tags,
        cefr,
        bandPosition,
        clauseCount,
        qualityScore,
        reviewStatus,
    };
}

function lowPersonRef(person: string, capitalize = false) {
    const base = /^[A-Z]/.test(person) ? person : `the ${person}`;
    if (!capitalize) return base;
    return `${base.charAt(0).toUpperCase()}${base.slice(1)}`;
}

