function lowRefineId(cefr: "A1" | "A2-" | "A2+", bandPosition: ListeningBandPosition, bundleIndex: number, variantIndex: number) {
    const bucket = cefr === "A1" ? "a1" : cefr === "A2-" ? "a2m" : "a2p";
    return `listen-refine-${bucket}-${bandPosition}-${String(bundleIndex + 1).padStart(2, "0")}-${String(variantIndex + 1).padStart(2, "0")}`;
}

function buildA1RefinedSeeds(bundle: LowRefinementBundle, bandPosition: ListeningBandPosition, bundleIndex: number): LowBandSeed[] {
    const variants = bandPosition === "entry"
        ? [
            { zh: `把${bundle.itemZh}带上。`, en: `Bring the ${bundle.itemEn} with you.` },
            { zh: `${bundle.itemZh}在${bundle.placeZh}上。`, en: `The ${bundle.itemEn} is on the ${bundle.placeEn}.` },
            { zh: `${bundle.personZh}把${bundle.itemZh}放那儿了。`, en: `${bundle.personEn} left the ${bundle.itemEn} there.` },
            { zh: `把你的${bundle.itemZh}放在${bundle.placeZh}边。`, en: `Put your ${bundle.itemEn} by the ${bundle.placeEn}.` },
        ]
        : bandPosition === "mid"
            ? [
                { zh: `请把${bundle.itemZh}放在${bundle.placeZh}上。`, en: `Please keep the ${bundle.itemEn} on the ${bundle.placeEn}.` },
                { zh: `${bundle.personZh}把你的${bundle.itemZh}放在${bundle.placeZh}边。`, en: `${bundle.personEn} left your ${bundle.itemEn} by the ${bundle.placeEn}.` },
                { zh: `现在把${bundle.itemZh}放到${bundle.placeZh}下面。`, en: `Put the ${bundle.itemEn} under the ${bundle.placeEn} now.` },
                { zh: `把${bundle.itemZh}拿回${bundle.placeZh}那边。`, en: `Bring the ${bundle.itemEn} back to the ${bundle.placeEn}.` },
            ]
            : [
                { zh: `请把${bundle.itemZh}留在${bundle.placeZh}边。`, en: `Please leave the ${bundle.itemEn} by the ${bundle.placeEn}.` },
                { zh: `${bundle.personZh}把${bundle.itemZh}放在${bundle.placeZh}附近。`, en: `${bundle.personEn} put the ${bundle.itemEn} near the ${bundle.placeEn}.` },
                { zh: `把${bundle.itemZh}拿到${bundle.placeZh}那边去。`, en: `Take the ${bundle.itemEn} down to the ${bundle.placeEn}.` },
                { zh: `把你的${bundle.itemZh}放在${bundle.placeZh}旁边。`, en: `Keep your ${bundle.itemEn} beside the ${bundle.placeEn}.` },
            ];

    return variants.map((variant, variantIndex) => seed(
        lowRefineId("A1", bandPosition, bundleIndex, variantIndex),
        variant.zh,
        variant.en,
        [bundle.itemEn, bundle.placeEn],
        bundle.theme,
        bundle.scene,
        ["curated", "refined", "a1", bandPosition],
        "A1",
        bandPosition,
        0,
        0.97,
        "curated",
    ));
}

function buildA2MinusRefinedSeeds(bundle: LowRefinementBundle, bandPosition: ListeningBandPosition, bundleIndex: number): LowBandSeed[] {
    const person = lowPersonRef(bundle.personEn, true);
    const variants = bandPosition === "entry"
        ? [
            { zh: `请在午饭前把${bundle.itemZh}放到${bundle.placeZh}上。`, en: `Please leave the ${bundle.itemEn} on the ${bundle.placeEn} before lunch.` },
            { zh: `${bundle.personZh}课后把${bundle.itemZh}挪到了${bundle.placeZh}那边。`, en: `${person} moved the ${bundle.itemEn} to the ${bundle.placeEn} after class.` },
            { zh: `我今天早上把你的${bundle.itemZh}放在了${bundle.placeZh}边。`, en: `I left your ${bundle.itemEn} by the ${bundle.placeEn} this morning.` },
            { zh: `先把${bundle.itemZh}放在${bundle.placeZh}附近，开会要用。`, en: `Keep the ${bundle.itemEn} near the ${bundle.placeEn} for the meeting.` },
        ]
        : bandPosition === "mid"
            ? [
                { zh: `今天练习后请把${bundle.itemZh}带到${bundle.placeZh}那边。`, en: `Please bring the ${bundle.itemEn} to the ${bundle.placeEn} after practice today.` },
                { zh: `${bundle.personZh}休息时一直把${bundle.itemZh}放在${bundle.placeZh}边。`, en: `${person} kept the ${bundle.itemEn} near the ${bundle.placeEn} during the break.` },
                { zh: `上课前我把${bundle.itemZh}放到了${bundle.placeZh}上。`, en: `I put the ${bundle.itemEn} on the ${bundle.placeEn} before the lesson.` },
                { zh: `${bundle.itemZh}整个会都放在${bundle.placeZh}边上。`, en: `The ${bundle.itemEn} stayed by the ${bundle.placeEn} through the whole meeting.` },
            ]
            : [
                { zh: `出门前请把${bundle.itemZh}放在${bundle.placeZh}边。`, en: `Please leave the ${bundle.itemEn} by the ${bundle.placeEn} before you head out.` },
                { zh: `${bundle.personZh}午饭后把${bundle.itemZh}留在了${bundle.placeZh}那边。`, en: `${person} left the ${bundle.itemEn} near the ${bundle.placeEn} after lunch.` },
                { zh: `先把${bundle.itemZh}放在${bundle.placeZh}旁边，等我回来。`, en: `Keep the ${bundle.itemEn} beside the ${bundle.placeEn} till I get back.` },
                { zh: `下午那节课前我把${bundle.itemZh}放在了${bundle.placeZh}边。`, en: `I left the ${bundle.itemEn} by the ${bundle.placeEn} before the afternoon class.` },
            ];

    return variants.map((variant, variantIndex) => seed(
        lowRefineId("A2-", bandPosition, bundleIndex, variantIndex),
        variant.zh,
        variant.en,
        [bundle.itemEn, bundle.placeEn],
        bundle.theme,
        bundle.scene,
        ["curated", "refined", "a2m", bandPosition],
        "A2-",
        bandPosition,
        0,
        0.97,
        "curated",
    ));
}

function buildA2PlusRefinedSeeds(bundle: LowRefinementBundle, bandPosition: ListeningBandPosition, bundleIndex: number): LowBandSeed[] {
    const person = lowPersonRef(bundle.personEn);
    const variants = bandPosition === "entry"
        ? [
            { zh: `等${bundle.itemZh}送到${bundle.placeZh}后给我打电话。`, en: `Call me when the ${bundle.itemEn} gets to the ${bundle.placeEn}.` },
            { zh: `如果${bundle.itemZh}不见了，先去看${bundle.placeZh}。`, en: `If the ${bundle.itemEn} goes missing, check the ${bundle.placeEn} first.` },
            { zh: `我留在那儿了，因为${bundle.itemZh}还在${bundle.placeZh}上。`, en: `I stayed back because the ${bundle.itemEn} was still on the ${bundle.placeEn}.` },
            { zh: `${bundle.personZh}发消息后，我把${bundle.itemZh}挪到了${bundle.placeZh}那边。`, en: `When ${person} texted, I moved the ${bundle.itemEn} to the ${bundle.placeEn}.` },
        ]
        : bandPosition === "mid"
            ? [
                { zh: `如果${bundle.itemZh}看着还是不对，就把它拿到${bundle.placeZh}那边。`, en: `If the ${bundle.itemEn} still looks off, bring it over to the ${bundle.placeEn}.` },
                { zh: `我在${bundle.placeZh}边等了一会，因为${bundle.personZh}手里还拿着${bundle.itemZh}。`, en: `I waited by the ${bundle.placeEn} because ${person} still had the ${bundle.itemEn}.` },
                { zh: `队伍终于动起来后，我们把${bundle.itemZh}搬回了${bundle.placeZh}那边。`, en: `When the line finally moved, we carried the ${bundle.itemEn} back to the ${bundle.placeEn}.` },
                { zh: `等${bundle.personZh}把${bundle.itemZh}放到${bundle.placeZh}上后给我打电话。`, en: `Call me once ${person} leaves the ${bundle.itemEn} on the ${bundle.placeEn}.` },
            ]
            : [
                { zh: `如果没看到${bundle.itemZh}，出门前先去看${bundle.placeZh}那边。`, en: `If the ${bundle.itemEn} isn't there, check the ${bundle.placeEn} before you leave.` },
                { zh: `${bundle.personZh}回来后，我把${bundle.itemZh}从${bundle.placeZh}边挪开了。`, en: `When ${person} came back, I moved the ${bundle.itemEn} away from the ${bundle.placeEn}.` },
                { zh: `我又多留了一会，因为${bundle.itemZh}还在${bundle.placeZh}边上。`, en: `I stayed a little longer because the ${bundle.itemEn} was still by the ${bundle.placeEn}.` },
                { zh: `等${bundle.itemZh}课后送到${bundle.placeZh}那边时发消息给我。`, en: `Text me when the ${bundle.itemEn} gets to the ${bundle.placeEn} after class.` },
            ];

    return variants.map((variant, variantIndex) => seed(
        lowRefineId("A2+", bandPosition, bundleIndex, variantIndex),
        variant.zh,
        variant.en,
        [bundle.itemEn, bundle.placeEn],
        bundle.theme,
        bundle.scene,
        ["curated", "refined", "a2p", bandPosition],
        "A2+",
        bandPosition,
        1,
        0.98,
        "curated",
    ));
}

const REFINEMENT_BATCH_004: LowBandSeed[] = LOW_REFINEMENT_BUNDLES.flatMap((bundle, bundleIndex) => ([
    ...buildA1RefinedSeeds(bundle, "entry", bundleIndex),
    ...buildA1RefinedSeeds(bundle, "mid", bundleIndex),
    ...buildA1RefinedSeeds(bundle, "exit", bundleIndex),
    ...buildA2MinusRefinedSeeds(bundle, "entry", bundleIndex),
    ...buildA2MinusRefinedSeeds(bundle, "mid", bundleIndex),
    ...buildA2MinusRefinedSeeds(bundle, "exit", bundleIndex),
    ...buildA2PlusRefinedSeeds(bundle, "entry", bundleIndex),
    ...buildA2PlusRefinedSeeds(bundle, "mid", bundleIndex),
    ...buildA2PlusRefinedSeeds(bundle, "exit", bundleIndex),
]));

